     1→"use client";
     2→
     3→import { useMemo } from "react";
     4→import useSWR from "swr";
     5→import Link from "next/link";
     6→import { marked } from "marked";
     7→import {
     8→  releases as releasesApi,
     9→  sources as sourcesApi,
    10→  semanticReleases as srApi,
    11→  projects as projectsApi,
    12→} from "@/lib/api/client";
    13→import { ProviderBadge } from "@/components/ui/provider-badge";
    14→import { VersionChip } from "@/components/ui/version-chip";
    15→import type { SemanticRelease, Source, Project } from "@/lib/api/types";
    16→import { ArrowLeft, ExternalLink } from "lucide-react";
    17→
    18→import { timeAgo } from "@/lib/format";
    19→import { getPathSegment } from "@/lib/path";
    20→
    21→/* ------------------------------------------------------------------ */
    22→/*  Helpers                                                            */
    23→/* ------------------------------------------------------------------ */
    24→
    25→/** Returns true if the string already contains HTML tags. */
    26→function looksLikeHtml(s: string): boolean {
    27→  return /<[a-z][\s\S]*>/i.test(s);
    28→}
    29→
    30→/** Convert changelog to HTML — pass through if already HTML, otherwise render as markdown. */
    31→function changelogToHtml(raw: string): string {
    32→  if (looksLikeHtml(raw)) return raw;
    33→  return marked.parse(raw, { async: false }) as string;
    34→}
    35→
    36→function getProviderUrl(
    37→  provider: string,
    38→  repository: string,
    39→  version: string
    40→): string | null {
    41→  switch (provider) {
    42→    case "github":
    43→      return `https://github.com/${repository}/releases/tag/${version}`;
    44→    case "dockerhub":
    45→      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    46→    case "ecr-public":
    47→      return `https://gallery.ecr.aws/${repository}`;
    48→    case "gitlab":
    49→      return `https://gitlab.com/${repository}/-/releases/${version}`;
    50→    default:
    51→      return null;
    52→  }
    53→}
    54→
    55→function getProviderLabel(provider: string): string {
    56→  switch (provider) {
    57→    case "github":
    58→      return "GitHub";
    59→    case "dockerhub":
    60→      return "Docker Hub";
    61→    case "ecr-public":
    62→      return "ECR Public";
    63→    case "gitlab":
    64→      return "GitLab";
    65→    default:
    66→      return provider;
    67→  }
    68→}
    69→
    70→/* ------------------------------------------------------------------ */
    71→/*  Component                                                          */
    72→/* ------------------------------------------------------------------ */
    73→
    74→export function ReleaseDetail() {
    75→  // Read ID from URL path — useParams() returns stale "0" in static export
    76→  const id = getPathSegment(1); // /releases/{id}
    77→  /* Fetch release */
    78→  const { data: releaseData, isLoading } = useSWR(`release-${id}`, () =>
    79→    releasesApi.get(id)
    80→  );
    81→
    82→  const release = releaseData?.data;
    83→
    84→  /* Fetch source info once we have the release */
    85→  const { data: sourceData } = useSWR(
    86→    release ? `source-${release.source_id}` : null,
    87→    () => (release ? sourcesApi.get(release.source_id) : null)
    88→  );
    89→  const source: Source | undefined = sourceData?.data;
    90→
    91→  /* Fetch project info once we have the source */
    92→  const { data: projectData } = useSWR(
    93→    source ? `project-${source.project_id}` : null,
    94→    () => (source ? projectsApi.get(source.project_id) : null)
    95→  );
    96→  const project: Project | undefined = projectData?.data;
    97→
    98→  /* Fetch linked semantic releases (via project) */
    99→  const { data: srData } = useSWR(
   100→    source ? `sr-for-release-${id}` : null,
   101→    async () => {
   102→      if (!source) return [];
   103→      const res = await srApi.list(source.project_id, 1).catch(() => null);
   104→      if (!res?.data) return [];
   105→      /* Filter semantic releases whose version matches this release version */
   106→      return res.data.filter((sr: SemanticRelease) => sr.version === release?.version);
   107→    }
   108→  );
   109→
   110→  const linkedSRs: SemanticRelease[] = srData ?? [];
   111→
   112→  /* Memoize changelog HTML conversion */
   113→  const changelogHtml = useMemo(() => {
   114→    const raw = release?.raw_data?.changelog;
   115→    if (!raw) return null;
   116→    return changelogToHtml(String(raw));
   117→  }, [release?.raw_data?.changelog]);
   118→
   119→  /* Loading state */
   120→  if (isLoading) {
   121→    return (
   122→      <div
   123→        className="py-16 text-center"
   124→        style={{
   125→          fontFamily: "var(--font-dm-sans)",
   126→          fontSize: "13px",
   127→          color: "#6b7280",
   128→        }}
   129→      >
   130→        Loading...
   131→      </div>
   132→    );
   133→  }
   134→
   135→  if (!release) {
   136→    return (
   137→      <div className="py-16 text-center">
   138→        <p
   139→          style={{
   140→            fontFamily: "var(--font-fraunces)",
   141→            fontStyle: "italic",
   142→            fontSize: "15px",
   143→            color: "#9ca3af",
   144→          }}
   145→        >
   146→          Release not found
   147→        </p>
   148→      </div>
   149→    );
   150→  }
   151→
   152→  return (
   153→    <div className="space-y-8">
   154→      {/* Back link */}
   155→      <Link
   156→        href="/releases"
   157→        className="inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
   158→        style={{
   159→          fontFamily: "var(--font-dm-sans)",
   160→          fontSize: "13px",
   161→          color: "#6b7280",
   162→        }}
   163→      >
   164→        <ArrowLeft size={14} />
   165→        Back to Releases
   166→      </Link>
   167→
   168→      {/* Header */}
   169→      <div>
   170→        <h1
   171→          style={{
   172→            fontFamily: "var(--font-fraunces)",
   173→            fontSize: "24px",
   174→            fontWeight: 700,
   175→            color: "#111113",
   176→          }}
   177→        >
   178→          Release {release.version}
   179→        </h1>
   180→        <div className="mt-2 flex items-center gap-3">
   181→          {source && <ProviderBadge provider={source.provider} />}
   182→          {source && (
   183→            <span
   184→              style={{
   185→                fontFamily: "'JetBrains Mono', monospace",
   186→                fontSize: "12px",
   187→                color: "#374151",
   188→              }}
   189→            >
   190→              {source.repository}
   191→            </span>
   192→          )}
   193→          <VersionChip version={release.version} />
   194→          {source && (() => {
   195→            const url = getProviderUrl(source.provider, source.repository, release.version);
   196→            return url ? (
   197→              <a
   198→                href={url}
   199→                target="_blank"
   200→                rel="noopener noreferrer"
   201→                className="inline-flex items-center gap-1 transition-colors hover:opacity-70"
   202→                style={{
   203→                  fontFamily: "var(--font-dm-sans)",
   204→                  fontSize: "12px",
   205→                  color: "#e8601a",
   206→                }}
   207→              >
   208→                View on {getProviderLabel(source.provider)}
   209→                <ExternalLink size={12} />
   210→              </a>
   211→            ) : null;
   212→          })()}
   213→        </div>
   214→        {project && (
   215→          <p
   216→            className="mt-2"
   217→            style={{
   218→              fontFamily: "var(--font-dm-sans)",
   219→              fontSize: "13px",
   220→              color: "#6b7280",
   221→            }}
   222→          >
   223→            Project:{" "}
   224→            <Link
   225→              href={`/projects/${project.id}`}
   226→              className="hover:underline"
   227→              style={{ color: "#e8601a" }}
   228→            >
   229→              {project.name}
   230→            </Link>
   231→          </p>
   232→        )}
   233→      </div>
   234→
   235→      {/* Info grid */}
   236→      <div className="grid gap-6 lg:grid-cols-2">
   237→        {/* Version Details card */}
   238→        <div
   239→          className="rounded-lg bg-white"
   240→          style={{ border: "1px solid #e8e8e5" }}
   241→        >
   242→          <div
   243→            className="px-5 py-4"
   244→            style={{ borderBottom: "1px solid #e8e8e5" }}
   245→          >
   246→            <h2
   247→              style={{
   248→                fontFamily: "var(--font-fraunces)",
   249→                fontSize: "16px",
   250→                fontWeight: 600,
   251→                color: "#111113",
   252→              }}
   253→            >
   254→              Version Details
   255→            </h2>
   256→          </div>
   257→          <div className="space-y-3 px-5 py-4">
   258→            <DetailRow label="Version" value={release.version} mono />
   259→            <DetailRow
   260→              label="Source ID"
   261→              value={release.source_id}
   262→              mono
   263→              small
   264→            />
   265→            {source && (
   266→              <>
   267→                <DetailRow label="Provider" value={source.provider} />
   268→                <DetailRow label="Repository" value={source.repository} mono />
   269→              </>
   270→            )}
   271→            {release.released_at && (
   272→              <DetailRow
   273→                label="Released At"
   274→                value={new Date(release.released_at).toLocaleString()}
   275→              />
   276→            )}
   277→            <DetailRow
   278→              label="Ingested At"
   279→              value={new Date(release.created_at).toLocaleString()}
   280→            />
   281→            <DetailRow
   282→              label="Age"
   283→              value={timeAgo(release.released_at ?? release.created_at)}
   284→            />
   285→          </div>
   286→        </div>
   287→
   288→        {/* Linked Semantic Releases */}
   289→        <div
   290→          className="rounded-lg bg-white"
   291→          style={{ border: "1px solid #e8e8e5" }}
   292→        >
   293→          <div
   294→            className="px-5 py-4"
   295→            style={{ borderBottom: "1px solid #e8e8e5" }}
   296→          >
   297→            <h2
   298→              style={{
   299→                fontFamily: "var(--font-fraunces)",
   300→                fontSize: "16px",
   301→                fontWeight: 600,
   302→                color: "#111113",
   303→              }}
   304→            >
   305→              Semantic Releases
   306→            </h2>
   307→          </div>
   308→          <div className="px-5 py-4">
   309→            {linkedSRs.length > 0 ? (
   310→              <div className="space-y-3">
   311→                {linkedSRs.map((sr) => (
   312→                  <Link
   313→                    key={sr.id}
   314→                    href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}
   315→                    className="block rounded-lg px-4 py-3 transition-colors hover:bg-[#fafaf9]"
   316→                    style={{ border: "1px solid #e8e8e5" }}
   317→                  >
   318→                    <div className="flex items-center justify-between">
   319→                      <VersionChip version={sr.version} />
   320→                      <span
   321→                        className="rounded-full px-2 py-0.5"
   322→                        style={{
   323→                          fontFamily: "var(--font-dm-sans)",
   324→                          fontSize: "11px",
   325→                          fontWeight: 500,
   326→                          color:
   327→                            sr.status === "completed" ? "#16a34a" : "#e8601a",
   328→                          backgroundColor:
   329→                            sr.status === "completed" ? "#f0fdf4" : "#fff7ed",
   330→                        }}
   331→                      >
   332→                        {sr.status}
   333→                      </span>
   334→                    </div>
   335→                    {sr.report?.summary && (
   336→                      <p
   337→                        className="mt-2 line-clamp-2"
   338→                        style={{
   339→                          fontFamily: "var(--font-dm-sans)",
   340→                          fontStyle: "italic",
   341→                          fontSize: "13px",
   342→                          color: "#6b7280",
   343→                        }}
   344→                      >
   345→                        {sr.report.summary}
   346→                      </p>
   347→                    )}
   348→                    <p
   349→                      className="mt-1"
   350→                      style={{
   351→                        fontFamily: "var(--font-dm-sans)",
   352→                        fontSize: "12px",
   353→                        color: "#9ca3af",
   354→                      }}
   355→                    >
   356→                      {timeAgo(sr.created_at)}
   357→                    </p>
   358→                  </Link>
   359→                ))}
   360→              </div>
   361→            ) : (
   362→              <div className="py-6 text-center">
   363→                <p
   364→                  style={{
   365→                    fontFamily: "var(--font-fraunces)",
   366→                    fontStyle: "italic",
   367→                    fontSize: "14px",
   368→                    color: "#9ca3af",
   369→                  }}
   370→                >
   371→                  No semantic releases linked
   372→                </p>
   373→              </div>
   374→            )}
   375→          </div>
   376→        </div>
   377→      </div>
   378→
   379→      {/* Release Notes */}
   380→      <div
   381→        className="rounded-lg bg-white"
   382→        style={{ border: "1px solid #e8e8e5" }}
   383→      >
   384→        <div
   385→          className="px-5 py-4"
   386→          style={{ borderBottom: "1px solid #e8e8e5" }}
   387→        >
   388→          <h2
   389→            style={{
   390→              fontFamily: "var(--font-fraunces)",
   391→              fontSize: "16px",
   392→              fontWeight: 600,
   393→              color: "#111113",
   394→            }}
   395→          >
   396→            Release Notes
   397→          </h2>
   398→        </div>
   399→        <div className="px-5 py-4">
   400→          {changelogHtml ? (
   401→            <div
   402→              className="release-notes-content"
   403→              style={{
   404→                fontFamily: "var(--font-dm-sans)",
   405→                fontSize: "13px",
   406→                lineHeight: 1.7,
   407→                color: "#374151",
   408→              }}
   409→              dangerouslySetInnerHTML={{
   410→                __html: changelogHtml,
   411→              }}
   412→            />
   413→          ) : (
   414→            <p
   415→              style={{
   416→                fontFamily: "var(--font-fraunces)",
   417→                fontStyle: "italic",
   418→                fontSize: "14px",
   419→                color: "#9ca3af",
   420→              }}
   421→            >
   422→              No release notes available
   423→            </p>
   424→          )}
   425→        </div>
   426→      </div>
   427→    </div>
   428→  );
   429→}
   430→
   431→/* ------------------------------------------------------------------ */
   432→/*  Sub-components                                                     */
   433→/* ------------------------------------------------------------------ */
   434→
   435→function DetailRow({
   436→  label,
   437→  value,
   438→  mono,
   439→  small,
   440→}: {
   441→  label: string;
   442→  value: string;
   443→  mono?: boolean;
   444→  small?: boolean;
   445→}) {
   446→  return (
   447→    <div className="flex items-baseline justify-between gap-4">
   448→      <span
   449→        style={{
   450→          fontFamily: "var(--font-dm-sans)",
   451→          fontSize: "13px",
   452→          color: "#9ca3af",
   453→        }}
   454→      >
   455→        {label}
   456→      </span>
   457→      <span
   458→        className="text-right"
   459→        style={{
   460→          fontFamily: mono ? "'JetBrains Mono', monospace" : "var(--font-dm-sans)",
   461→          fontSize: small ? "11px" : "13px",
   462→          color: "#374151",
   463→        }}
   464→      >
   465→        {value}
   466→      </span>
   467→    </div>
   468→  );
   469→}
