    15→// glRelease represents a single release from the GitLab REST API v4.
    16→type glRelease struct {
    17→	TagName         string  `json:"tag_name"`
    18→	Description     string  `json:"description"`
    19→	ReleasedAt      string  `json:"released_at"`
    20→	UpcomingRelease bool    `json:"upcoming_release"`
    21→	Links           glLinks `json:"_links"`
    22→}
