    28→// GitLabSource polls the GitLab REST API v4 for project releases.
    29→type GitLabSource struct {
    30→	client     *http.Client
    31→	repository string
    32→	baseURL    string
    33→	sourceID   string
    34→}
    35→
    36→func NewGitLabSource(client *http.Client, repository string, sourceID string) *GitLabSource {
    37→	return &GitLabSource{
    38→		client:     client,
    39→		repository: repository,
    40→		baseURL:    defaultGitLabAPIURL,
    41→		sourceID:   sourceID,
    42→	}
    43→}
    44→
    45→func (s *GitLabSource) Name() string     { return "gitlab" }
    46→func (s *GitLabSource) SourceID() string { return s.sourceID }
    47→
    48→func (s *GitLabSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
    49→	encoded := url.PathEscape(s.repository)
    50→	apiURL := fmt.Sprintf("%s/api/v4/projects/%s/releases?per_page=20", s.baseURL, encoded)
    51→
    52→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, apiURL, nil)
    53→	if err != nil {
    54→		return nil, fmt.Errorf("create request: %w", err)
    55→	}
    56→
    57→	if token := os.Getenv("GITLAB_TOKEN"); token != "" {
    58→		req.Header.Set("PRIVATE-TOKEN", token)
    59→	}
    60→
    61→	resp, err := s.client.Do(req)
    62→	if err != nil {
    63→		return nil, fmt.Errorf("fetch releases: %w", err)
    64→	}
    65→	defer resp.Body.Close()
    66→
    67→	if resp.StatusCode != http.StatusOK {
    68→		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
    69→	}
    70→
    71→	var releases []glRelease
    72→	if err := json.NewDecoder(resp.Body).Decode(&releases); err != nil {
    73→		return nil, fmt.Errorf("decode releases: %w", err)
    74→	}
    75→
    76→	results := make([]IngestionResult, 0, len(releases))
    77→	for _, rel := range releases {
    78→		if rel.TagName == "" {
    79→			continue
    80→		}
    81→
    82→		ts, _ := time.Parse(time.RFC3339, rel.ReleasedAt)
    83→
    84→		prerelease := "false"
    85→		if rel.UpcomingRelease {
    86→			prerelease = "true"
    87→		}
    88→
    89→		results = append(results, IngestionResult{
    90→			Repository: s.repository,
    91→			RawVersion: rel.TagName,
    92→			Changelog:  rel.Description,
    93→			Metadata: map[string]string{
    94→				"release_url": rel.Links.Self,
    95→				"prerelease":  prerelease,
    96→			},
    97→			Timestamp: ts,
    98→		})
    99→	}
   100→	return results, nil
   101→}
